// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
#define MAX_Q 100005
// Define the structure for a tree node
typedef struct Node {
    int id;
    int parent;
    int children[MAX_N];
    int numChildren;
} Node;
// Define the structure for a query
typedef struct Query {
    int R;
    int A;
    int B;
    int X;
    int Y;
} Query;
// Function to calculate the cost of traversal
int calculateCost(Node *tree, int node, int parent, int A, int B, int depth) {
    int cost = 0;
    if (parent != -1) {
        if (depth > 0) {
            cost += depth * A;
        } else {
            cost += -depth * B;
        }
    }
    return cost;
}
// Function to find the shortest path between two nodes
int findShortestPath(Node *tree, int X, int Y, int R, int A, int B) {
    int cost = 0;
    // Find the path from X to R
    int currentNode = X;
    int parent = -1;
    int depth = 0;
    while (currentNode != R) {
        cost += calculateCost(tree, currentNode, parent, A, B, depth);
        parent = currentNode;
        currentNode = tree[currentNode].parent;
        depth++;
    }
    // Find the path from Y to R
    currentNode = Y;
    parent = -1;
    depth = 0;
    while (currentNode != R) {
        cost += calculateCost(tree, currentNode, parent, A, B, depth);
        parent = currentNode;
        currentNode = tree[currentNode].parent;
        depth++;
    }
    return cost;
}
int main() {
    int N;
    scanf("%d", &N);
    Node tree[N + 1];
    for (int i = 1; i <= N; i++) {
        tree[i].id = i;
        tree[i].parent = -1;
        tree[i].numChildren = 0;
    }
    for (int i = 1; i < N; i++) {
        int U, V;
        scanf("%d %d", &U, &V);
        tree[U].children[tree[U].numChildren++] = V;
        tree[V].parent = U;
    }
    int Q;
    scanf("%d", &Q);
    Query queries[Q];
    for (int i = 0; i < Q; i++) {
        scanf("%d %d %d %d %d", &queries[i].R, &queries[i].A, &queries[i].B, &queries[i].X, &queries[i].Y);
    }
    for (int i = 0; i < Q; i++) {
        int cost = findShortestPath(tree, queries[i].X, queries[i].Y, queries[i].R, queries[i].A, queries[i].B);
        printf("%d\n", cost);
    }
    return 0;
}

