            this.id = id;
            this.parent = -1;
            this.children = new ArrayList<>();
        }
    }
    static class Query {
        int R;
        int A;
        int B;
        int X;
        int Y;
        public Query(int R, int A, int B, int X, int Y) {
            this.R = R;
            this.A = A;
            this.B = B;
            this.X = X;
            this.Y = Y;
        }
    }
    public static int calculateCost(Node[] tree, int node, int parent, int A, int B, int depth) {
        int cost = 0;
        if (parent != -1) {
            if (depth > 0) {
                cost += depth * A;
            } else {
                cost += -depth * B;
            }
        }
        return cost;
    }
    public static int findShortestPath(Node[] tree, int X, int Y, int R, int A, int B) {
        int cost = 0;
        // Find the path from X to R
        int currentNode = X;
        int parent = -1;
        int depth = 0;
        while (currentNode != R) {
            cost += calculateCost(tree, currentNode, parent, A, B, depth);
            parent = currentNode;
            currentNode = tree[currentNode].parent;
            depth++;
        }
        // Find the path from Y to R
        currentNode = Y;
        parent = -1;
        depth = 0;
        while (currentNode != R) {
            cost += calculateCost(tree, currentNode, parent, A, B, depth);
            parent = currentNode;
            currentNode = tree[currentNode].parent;
            depth++;
        }
        return cost;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Node[] tree = new Node[N + 1];
        for (int i = 1; i <= N; i++) {
            tree[i] = new Node(i);
        }
        for (int i = 1; i < N; i++) {
            int U = scanner.nextInt();
            int V = scanner.nextInt();
            tree[U].children.add(V);
            tree[V].parent = U;
        }
        int Q = scanner.nextInt();
        Query[] queries = new Query[Q];
        for (int i = 0; i < Q; i++) {
            int R = scanner.nextInt();
            int A = scanner.nextInt();
            int B = scanner.nextInt();
            int X = scanner.nextInt();
            int Y = scanner.nextInt();
            queries[i] = new Query(R, A, B, X, Y);
        }
        for (int i = 0; i < Q; i++) {
            int cost = findShortestPath(tree, queries[i].X, queries[i].Y, queries[i].R, queries[i].A, queries[i].B);
